import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { getTasks, createTask, deleteTask } from "../services/TaskService";
import TaskForm from "../components/TaskForm";
import TaskList from "../components/TaskList";

const HomePage = () => {
  const [user, setUser] = useState(null);
  const [tasks, setTasks] = useState([]);
  const [categories, setCategories] = useState([{ id: 1, title: "General" }]);
  const navigate = useNavigate();

  useEffect(() => {
    const savedUser = localStorage.getItem("loggedUser");
    const token = localStorage.getItem("token");

    // Verificamos si existe el usuario y el token de seguridad
    if (savedUser && token) {
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);
      fetchUserTasks(parsedUser.id);
    } else {
      // Si no está autenticado, lo expulsamos al login
      navigate("/login");
    }
  }, [navigate]);

  const fetchUserTasks = async (userId) => {
    try {
      const data = await getTasks(userId);
      setTasks(data);
    } catch (err) {
      console.error("Error al cargar tareas:", err);
    }
  };

  const handleCreateTask = async (taskData) => {
    try {
      const newTask = await createTask(taskData, user.id);
      setTasks([...tasks, newTask]);
    } catch (err) {
      alert("Error al crear la tarea");
    }
  };

  const handleDeleteTask = async (taskId) => {
    try {
      await deleteTask(taskId);
      setTasks(tasks.filter((t) => t.id !== taskId));
    } catch (err) {
      alert("Error al borrar la tarea");
    }
  };

  if (!user) return <div>Cargando...</div>;

  return (
    <div style={{ padding: "20px" }}>
      <header
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
        }}
      >
        <h1>Mis Tareas - {user.username}</h1>
        <button
          onClick={() => {
            // Cerramos sesión borrando tanto los datos como el Token
            localStorage.removeItem("loggedUser");
            localStorage.removeItem("token");
            navigate("/login");
          }}
        >
          Cerrar Sesión
        </button>
      </header>

      <hr />

      <TaskForm onTaskCreated={handleCreateTask} categories={categories} />

      <h2>Tu Lista</h2>
      <TaskList tasks={tasks} onDelete={handleDeleteTask} />
    </div>
  );
};

export default HomePage;
